mapping_residual('cdc-2022-opioid','box3.grp.03','residual.grp03.01',class(scope_deferred),detail(quote('Deciding Duration of Initial Opioid Prescription and Conducting Follow-Up (Recommendations 6 and 7)'),note('Needs grouping semantics that attach recommendations 6 and 7 to the prescription-duration and follow-up decision phase.'))).
mapping_residual('cdc-2022-opioid','box3.grp.04','residual.grp04.01',class(scope_deferred),detail(quote('Assessing Risk and Addressing Potential Harms of Opioid Use (Recommendations 8, 9, 10, 11, and 12)'),note('Needs grouping semantics that attach recommendations 8 through 12 to the risk-assessment and harm-mitigation decision phase.'))).
