mapping_residual('cdc-2022-opioid','box3.rec.01','residual.rec01.04',class(scope_deferred),detail(quote('as appropriate for the specific condition and patient'),note('Needs condition-specific and patient-specific suitability qualifiers attached to the action.'))).
