mapping_residual('cdc-2022-opioid','box3.rec.02','residual.rec02.05',class(transitive_relation),detail(quote('clinicians should discuss with patients the realistic benefits and known risks of opioid therapy'),note('Needs a clinician-patient discussion relation whose content names benefits and risks.'))).
