mapping_residual('cdc-2022-opioid','box3.rec.03','residual.rec03.03',class(multi_entity),detail(quote('instead of extended-release and long-acting (ER/LA) opioids'),note('Needs a formulation-choice relation contrasting immediate-release with ER/LA entities.'))).
mapping_residual('cdc-2022-opioid','box3.rec.03','residual.rec03.04',class(direction_strength),detail(quote('recommendation category: A'),note('Needs an explicit constructor for recommendation category and direction strength.'))).
mapping_residual('cdc-2022-opioid','box3.rec.03','residual.rec03.05',class(certainty),detail(quote('evidence type: 4'),note('Needs an explicit constructor for evidence type and certainty.'))).
