mapping_residual('cdc-2022-opioid','box3.rec.04','residual.rec04.02',class(disjunction),detail(quote('acute, subacute, or chronic pain'),note('Needs explicit alternatives for the three pain-duration applicability classes.'))).
mapping_residual('cdc-2022-opioid','box3.rec.04','residual.rec04.03',class(dose_quantity),detail(quote('the lowest effective dosage'),note('Needs a dosage quantity constructor with minimum and effectiveness semantics.'))).
mapping_residual('cdc-2022-opioid','box3.rec.04','residual.rec04.04',class(labeled_exception),detail(quote('If opioids are continued for subacute or chronic pain'),note('Needs a labeled continuation branch with pain-duration scope.'))).
