mapping_residual('cdc-2022-opioid','box3.rec.04','residual.rec04.07',class(dose_quantity),detail(quote('avoid increasing dosage above levels likely to yield diminishing returns in benefits relative to risks to patients'),note('Needs dosage-threshold and diminishing-return comparison constructors.'))).
mapping_residual('cdc-2022-opioid','box3.rec.04','residual.rec04.08',class(direction_strength),detail(quote('recommendation category: A'),note('Needs an explicit constructor for recommendation category and direction strength.'))).
